import { useState, useEffect } from "react";
import { useSelector } from "react-redux";
import { Link } from "react-router-dom";
import { toast } from "react-toastify";
import Modal from "../components/Modal";

function Courses() {
  const [courses, setCourses] = useState([]);
  const [teachers, setTeachers] = useState([]);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [courseToDelete, setCourseToDelete] = useState(null);
  const user = useSelector((state) => state.auth.user);

  useEffect(() => {
    fetch("http://localhost:3001/courses")
      .then((res) => res.json())
      .then((data) => setCourses(data));
    fetch("http://localhost:3001/users?role=teacher")
      .then((res) => res.json())
      .then((data) => setTeachers(data));
  }, []);

  async function handleDelete() {
    const response = await fetch(`http://localhost:3001/courses/${courseToDelete}`, {
      method: "DELETE",
    });
    if (response.ok) {
      setCourses(courses.filter((c) => c.id !== courseToDelete));
      toast.success("Course deleted successfully!");
    } else {
      toast.error("Failed to delete course");
    }
    setIsModalOpen(false);
  }

  function openModal(courseId) {
    setCourseToDelete(courseId);
    setIsModalOpen(true);
  }

  return (
    <div className="page-container">
      <h1>Courses</h1>
      <ul>
        {courses.map((course) => (
          <li key={course.id}>
            {course.name} - {course.description} (Teacher: {teachers.find(t => t.id === course.teacherId)?.name || "Unknown"})
            {(user.role === "admin" || (user.role === "teacher" && course.teacherId === user.id)) && (
              <Link to={`/edit-course/${course.id}`}>
                <button>Edit</button>
              </Link>
            )}
            {user.role === "admin" && (
              <button onClick={() => openModal(course.id)}>Delete</button>
            )}
          </li>
        ))}
      </ul>
      <Modal
        isOpen={isModalOpen}
        onClose={() => setIsModalOpen(false)}
        onConfirm={handleDelete}
        message="Are you sure you want to delete this course?"
      />
    </div>
  );
}

export default Courses;
